221	static ngx_int_t
222	ngx_ssl_stapling_certificate(ngx_conf_t *cf, ngx_ssl_t *ssl, X509 *cert,
223	    ngx_str_t *file, ngx_str_t *responder, ngx_uint_t verify)
224	{
225	    ngx_int_t            rc;
226	    ngx_pool_cleanup_t  *cln;
227	    ngx_ssl_stapling_t  *staple;
228	
229	    staple = ngx_pcalloc(cf->pool, sizeof(ngx_ssl_stapling_t));
230	    if (staple == NULL) {
231	        return NGX_ERROR;
232	    }
233	
234	    cln = ngx_pool_cleanup_add(cf->pool, 0);
235	    if (cln == NULL) {
236	        return NGX_ERROR;
237	    }
238	
239	    cln->handler = ngx_ssl_stapling_cleanup;
240	    cln->data = staple;
241	
242	    staple->node.key = (ngx_rbtree_key_t) cert;
243	
244	    ngx_rbtree_insert(&ssl->staple_rbtree, &staple->node);
245	
246	#ifdef SSL_CTRL_SELECT_CURRENT_CERT
247	    /* OpenSSL 1.0.2+ */
248	    SSL_CTX_select_current_cert(ssl->ctx, cert);
249	#endif
250	
251	#ifdef SSL_CTRL_GET_EXTRA_CHAIN_CERTS
252	    /* OpenSSL 1.0.1+ */
253	    SSL_CTX_get_extra_chain_certs(ssl->ctx, &staple->chain);
254	#else
255	    staple->chain = ssl->ctx->extra_certs;
256	#endif
257	
258	    staple->ssl_ctx = ssl->ctx;
259	    staple->timeout = 60000;
260	    staple->verify = verify;
261	    staple->cert = cert;
262	    staple->name = X509_get_ex_data(staple->cert,
263	                                    ngx_ssl_certificate_name_index);
264	
265	    if (file->len) {
266	        /* use OCSP response from the file */
267	
268	        if (ngx_ssl_stapling_file(cf, ssl, staple, file) != NGX_OK) {
269	            return NGX_ERROR;
270	        }
271	
272	        return NGX_OK;
273	    }
274	
275	    rc = ngx_ssl_stapling_issuer(cf, ssl, staple);
276	
277	    if (rc == NGX_DECLINED) {
278	        return NGX_OK;
279	    }
280	
281	    if (rc != NGX_OK) {
282	        return NGX_ERROR;
283	    }
284	
285	    rc = ngx_ssl_stapling_responder(cf, ssl, staple, responder);
286	
287	    if (rc == NGX_DECLINED) {
288	        return NGX_OK;
289	    }
290	
291	    if (rc != NGX_OK) {
292	        return NGX_ERROR;
293	    }
294	
295	    return NGX_OK;
296	}
