299	static ngx_int_t
300	ngx_ssl_stapling_file(ngx_conf_t *cf, ngx_ssl_t *ssl,
301	    ngx_ssl_stapling_t *staple, ngx_str_t *file)
302	{
303	    BIO            *bio;
304	    int             len;
305	    u_char         *p, *buf;
306	    OCSP_RESPONSE  *response;
307	
308	    if (ngx_conf_full_name(cf->cycle, file, 1) != NGX_OK) {
309	        return NGX_ERROR;
310	    }
311	
312	    bio = BIO_new_file((char *) file->data, "rb");
313	    if (bio == NULL) {
314	        ngx_ssl_error(NGX_LOG_EMERG, ssl->log, 0,
315	                      "BIO_new_file(\"%s\") failed", file->data);
316	        return NGX_ERROR;
317	    }
318	
319	    response = d2i_OCSP_RESPONSE_bio(bio, NULL);
320	    if (response == NULL) {
321	        ngx_ssl_error(NGX_LOG_EMERG, ssl->log, 0,
322	                      "d2i_OCSP_RESPONSE_bio(\"%s\") failed", file->data);
323	        BIO_free(bio);
324	        return NGX_ERROR;
325	    }
326	
327	    len = i2d_OCSP_RESPONSE(response, NULL);
328	    if (len <= 0) {
329	        ngx_ssl_error(NGX_LOG_EMERG, ssl->log, 0,
330	                      "i2d_OCSP_RESPONSE(\"%s\") failed", file->data);
331	        goto failed;
332	    }
333	
334	    buf = ngx_alloc(len, ssl->log);
335	    if (buf == NULL) {
336	        goto failed;
337	    }
338	
339	    p = buf;
340	    len = i2d_OCSP_RESPONSE(response, &p);
341	    if (len <= 0) {
342	        ngx_ssl_error(NGX_LOG_EMERG, ssl->log, 0,
343	                      "i2d_OCSP_RESPONSE(\"%s\") failed", file->data);
344	        ngx_free(buf);
345	        goto failed;
346	    }
347	
348	    OCSP_RESPONSE_free(response);
349	    BIO_free(bio);
350	
351	    staple->staple.data = buf;
352	    staple->staple.len = len;
353	    staple->valid = NGX_MAX_TIME_T_VALUE;
354	
355	    return NGX_OK;
356	
357	failed:
358	
359	    OCSP_RESPONSE_free(response);
360	    BIO_free(bio);
361	
362	    return NGX_ERROR;
363	}
