366	static ngx_int_t
367	ngx_ssl_stapling_issuer(ngx_conf_t *cf, ngx_ssl_t *ssl,
368	    ngx_ssl_stapling_t *staple)
369	{
370	    int              i, n, rc;
371	    X509            *cert, *issuer;
372	    X509_STORE      *store;
373	    X509_STORE_CTX  *store_ctx;
374	
375	    cert = staple->cert;
376	
377	    n = sk_X509_num(staple->chain);
378	
379	    ngx_log_debug1(NGX_LOG_DEBUG_EVENT, ssl->log, 0,
380	                   "SSL get issuer: %d extra certs", n);
381	
382	    for (i = 0; i < n; i++) {
383	        issuer = sk_X509_value(staple->chain, i);
384	        if (X509_check_issued(issuer, cert) == X509_V_OK) {
385	#if OPENSSL_VERSION_NUMBER >= 0x10100001L
386	            X509_up_ref(issuer);
387	#else
388	            CRYPTO_add(&issuer->references, 1, CRYPTO_LOCK_X509);
389	#endif
390	
391	            ngx_log_debug1(NGX_LOG_DEBUG_EVENT, ssl->log, 0,
392	                           "SSL get issuer: found %p in extra certs", issuer);
393	
394	            staple->issuer = issuer;
395	
396	            return NGX_OK;
397	        }
398	    }
399	
400	    store = SSL_CTX_get_cert_store(ssl->ctx);
401	    if (store == NULL) {
402	        ngx_ssl_error(NGX_LOG_EMERG, ssl->log, 0,
403	                      "SSL_CTX_get_cert_store() failed");
404	        return NGX_ERROR;
405	    }
406	
407	    store_ctx = X509_STORE_CTX_new();
408	    if (store_ctx == NULL) {
409	        ngx_ssl_error(NGX_LOG_EMERG, ssl->log, 0,
410	                      "X509_STORE_CTX_new() failed");
411	        return NGX_ERROR;
412	    }
413	
414	    if (X509_STORE_CTX_init(store_ctx, store, NULL, NULL) == 0) {
415	        ngx_ssl_error(NGX_LOG_EMERG, ssl->log, 0,
416	                      "X509_STORE_CTX_init() failed");
417	        X509_STORE_CTX_free(store_ctx);
418	        return NGX_ERROR;
419	    }
420	
421	    rc = X509_STORE_CTX_get1_issuer(&issuer, store_ctx, cert);
422	
423	    if (rc == -1) {
424	        ngx_ssl_error(NGX_LOG_EMERG, ssl->log, 0,
425	                      "X509_STORE_CTX_get1_issuer() failed");
426	        X509_STORE_CTX_free(store_ctx);
427	        return NGX_ERROR;
428	    }
429	
430	    if (rc == 0) {
431	        ngx_log_error(NGX_LOG_WARN, ssl->log, 0,
432	                      "\"ssl_stapling\" ignored, "
433	                      "issuer certificate not found for certificate \"%s\"",
434	                      staple->name);
435	        X509_STORE_CTX_free(store_ctx);
436	        return NGX_DECLINED;
437	    }
438	
439	    X509_STORE_CTX_free(store_ctx);
440	
441	    ngx_log_debug1(NGX_LOG_DEBUG_EVENT, ssl->log, 0,
442	                   "SSL get issuer: found %p in cert store", issuer);
443	
444	    staple->issuer = issuer;
445	
446	    return NGX_OK;
447	}
