451	ngx_ssl_stapling_responder(ngx_conf_t *cf, ngx_ssl_t *ssl,
452	    ngx_ssl_stapling_t *staple, ngx_str_t *responder)
453	{
454	    char                      *s;
455	    ngx_str_t                  rsp;
456	    ngx_url_t                  u;
457	    STACK_OF(OPENSSL_STRING)  *aia;
